prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT DISTINCT ?model ?modelName ?origId ?normId WHERE {
  ?model a bboExt:Model .
  OPTIONAL { ?model bbo:name ?modelName . }
  OPTIONAL { ?model tai:originalId ?origId . }
  OPTIONAL { ?model tai:normalizedId ?normId . }
  FILTER(CONTAINS(STR(?origId), "2aa476e4bbdf451083ec316570f7a3be") 
         || CONTAINS(STR(?normId), "2aa476e4bbdf451083ec316570f7a3be"))
}
LIMIT 10

prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT DISTINCT ?mf ?mfName ?sourceName ?targetName ?sourceRef ?targetRef ?messageRef WHERE {
  ?mf a bboExt:MessageFlow .
  OPTIONAL { ?mf bbo:name ?mfName . }
  OPTIONAL { ?mf bboExt:sourceRef ?sourceRef . }
  OPTIONAL { ?mf bboExt:targetRef ?targetRef . }
  OPTIONAL { ?mf bboExt:messageRef ?messageRef . }

  # Get source and target participant names
  OPTIONAL {
    ?source a bboExt:Participant .
    ?source bbo:name ?sourceName .
    FILTER(STRENDS(STR(?source), ?sourceRef))
  }
  OPTIONAL {
    ?target a bboExt:Participant .
    ?target bbo:name ?targetName .
    FILTER(STRENDS(STR(?target), ?targetRef))
  }

  # Navigate to choreography
  ?mf tai:belongsTo ?choreo .
  ?choreo a bboExt:Choreography .

  # Navigate to model via definitions
  ?choreo tai:belongsTo ?defs .
  ?defs a bboExt:Definitions .
  ?defs tai:belongsTo ?model .
  ?model tai:originalId "2aa476e4bbdf451083ec316570f7a3be" .
}
LIMIT 50
